const config = $('Configuration').first().json;
const token = $json.access_token;
const days = Number(config.days || 0);
const now = new Date();
const baghdadOffset = 3 * 60;
const baghdadNow = new Date(now.getTime() + (baghdadOffset + now.getTimezoneOffset()) * 60000);
const target = new Date(baghdadNow);
target.setDate(target.getDate() + days);
const fromBaghdad = new Date(target.getFullYear(), target.getMonth(), target.getDate(), 0, 0, 0);
const toBaghdad = new Date(target.getFullYear(), target.getMonth(), target.getDate(), 23, 59, 59);
const fromUTC = new Date(fromBaghdad.getTime() - baghdadOffset * 60000).toISOString();
const toUTC = new Date(toBaghdad.getTime() - baghdadOffset * 60000).toISOString();
return [{ json: { access_token: token, fromExpirationDate: fromUTC, toExpirationDate: toUTC, pageNumber: 1, pageSize: 150, config: config } }];

const data = $input.first().json;
const items = data.items || [];
const config = $('Calculate Dates').first().json.config;
const token = $('Calculate Dates').first().json.access_token;
if (items.length === 0) return [];
return items.map(row => ({ json: { customer_id: row.customer?.id, customer_name: row.customer?.displayValue, service_name: row.services?.[0]?.displayValue || row.bundle?.displayValue, zone_name: row.zone?.displayValue, expires: row.expires, access_token: token, config: config } }));

const store = $getWorkflowStaticData('global');
if (!store.ready) store.ready = [];
if (!store.stats) store.stats = { total: 0, withPhone: 0, noPhone: 0, sent: 0, failed: 0 };
const prev = $('Split For Phones').first().json;
const phoneData = $input.first().json;
const phone = phoneData.model?.primaryContact?.mobile || '';
store.stats.total++;
let clean = phone.replace(/[^\d]/g, '');
if (clean.startsWith('0')) clean = '964' + clean.substring(1);
else if (!clean.startsWith('964')) clean = '964' + clean;
const valid = /^964\d{9,12}$/.test(clean) && clean.length >= 12;
if (valid) { store.stats.withPhone++; store.ready.push({ phone: clean, name: prev.customer_name || '', expires: prev.expires || '', config: prev.config }); }
else { store.stats.noPhone++; }
return [{ json: { processed: store.stats.total } }];

const store = $getWorkflowStaticData('global');
const ready = store.ready || [];
const stats = store.stats || {};
if (ready.length === 0) return [];
const result = ready.map(r => ({ json: r }));
store.ready = [];
return result;

const item = $json;
const config = item.config || $('Configuration').first().json;
let endDate = '';
try { const d = new Date(item.expires); endDate = d.toISOString().split('T')[0]; } catch(e) { endDate = item.expires || ''; }
return [{ json: { phone: item.phone, name: item.name, endDate: endDate, contactNumbers: config.contactNumbers || '07705210210' } }];

const store = $getWorkflowStaticData('global');
if (!store.stats) store.stats = { total: 0, withPhone: 0, noPhone: 0, sent: 0, failed: 0 };
const r = $json;
const prev = $('Prepare Message').first().json;
if (r.messages && r.messages.length > 0) { store.stats.sent++; } else { store.stats.failed++; }
return [{ json: { sent: !!(r.messages && r.messages.length > 0), phone: prev.phone, name: prev.name } }];

const d = $input.first().json;
const prev = $('Prepare Message').first().json;
const msg = '\u0639\u0632\u064a\u0632\u064a \u0627\u0644\u0645\u0634\u062a\u0631\u0643 ' + prev.name + '\n\u0627\u0634\u062a\u0631\u0627\u0643\u0643 \u0633\u064a\u0646\u062a\u0647\u064a \u0628\u062a\u0627\u0631\u064a\u062e ' + prev.endDate;
return [{ json: { phone: prev.phone, apiBody: { message: msg, type: 'template' } } }];

const store = $getWorkflowStaticData('global');
const stats = store.stats || { total: 0, withPhone: 0, noPhone: 0, sent: 0, failed: 0 };
const config = $('Configuration').first().json;
const now = new Date();
const bNow = new Date(now.getTime() + 180 * 60000);
const time = String(bNow.getHours()).padStart(2,'0') + ':' + String(bNow.getMinutes()).padStart(2,'0');
const date = bNow.toISOString().split('T')[0];
store.stats = null;
return [{ json: { total: stats.total, sent: stats.sent, failed: stats.failed, withPhone: stats.withPhone, noPhone: stats.noPhone, time: time, date: date, days: Number(config.days || 0), apiKey: config.apiKey, managerPhone: config.managerPhone, phoneNumberId: config.phoneNumberId, message: '\ud83d\udcca *' + '\u062a\u0642\u0631\u064a\u0631 \u0627\u0644\u062a\u0630\u0643\u064a\u0631' + '*\n\n' + date + ' - ' + time + '\n\n\u0627\u0644\u0645\u0634\u062a\u0631\u0643\u064a\u0646: *' + stats.total + '*\n\u0623\u0631\u0633\u0644: *' + stats.sent + '*\n\u0641\u0634\u0644: *' + stats.failed + '*' } }];
